**Stored Procedure: `delete_inactive_users`**

```sql
DELIMITER $$

CREATE PROCEDURE delete_inactive_users()
BEGIN
    DECLARE done INT DEFAULT 0;
    DECLARE user_id INT;
    DECLARE cursor_users CURSOR FOR SELECT user_id FROM users WHERE status = 'Inactive';
    DECLARE CONTINUE HANDLER FOR SQLSTATE '02000' SET done = 1;

    START TRANSACTION;

    -- Open the cursor for the users with 'Inactive' status
    OPEN cursor_users;

    -- Loop through each user
    read_loop: LOOP
        FETCH cursor_users INTO user_id;

        IF done = 1 THEN
            LEAVE read_loop;
        END IF;

        -- Delete the user from the 'users' table
        DELETE FROM users WHERE user_id = user_id;

        -- Log the deletion in the 'status_log' table
        INSERT INTO status_log (user_id, status, modification_date)
        VALUES (user_id, 'Active', CURRENT_TIMESTAMP);

    END LOOP;

    -- Close the cursor
    CLOSE cursor_users;

    COMMIT;
END $$

DELIMITER ;
```

